import { cursor } from './stores/cursor';
import { difficulty } from './stores/difficulty';
import { gamePaused } from './stores/game';
import { timer } from './stores/timer';
import { hints } from './stores/hints';
import { gameStore } from './stores/gameStore';

/**
 * Start new game with a generated sudoku
 *
 * @param {('veryeasy' | 'easy' | 'medium' | 'hard')} diff
 */
export function startNew(diff) {
	difficulty.set(diff);
	gameStore.startNew(diff);
	cursor.reset();
	timer.reset();
	hints.reset();

	location.hash = '';
}

/**
 * Start new game with a custom sudoku
 *
 * @param {string} sencode
 */
export function startCustom(sencode) {
	difficulty.setCustom();
	gameStore.startCustom(sencode);
	cursor.reset();
	timer.reset();
	hints.reset();
}

export function pauseGame() {
	timer.stop();
	gamePaused.set(true);
}

export function resumeGame() {
	timer.start();
	gamePaused.set(false);
}

export function undoGame() {
	return gameStore.undo();
}

export function redoGame() {
	return gameStore.redo();
}

export function enterExplore() {
	return gameStore.enterExplore();
}

export function abortExplore() {
	return gameStore.abortExplore();
}

export function commitExplore() {
	return gameStore.commitExplore();
}

export default {
	startNew,
	startCustom,
	pause: pauseGame,
	resume: resumeGame,
	undo: undoGame,
	redo: redoGame,
	enterExplore,
	abortExplore,
	commitExplore,
};
